import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import { addNotification } from "../notificationReducer";

function AddCourse() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const user = useSelector((state) => state.auth.user);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [file, setFile] = useState(null);

  const validFileTypes = [".pdf", ".docx", ".jpg", ".png"];

  async function handleSubmit(e) {
    e.preventDefault();

    if (!name || !description) {
      toast.error("Название и описание курса обязательны.");
      return;
    }

    if (file) {
      const fileExtension = file.name.slice(file.name.lastIndexOf(".")).toLowerCase();
      if (!validFileTypes.includes(fileExtension)) {
        toast.error("Недопустимый тип файла. Допустимы: .pdf, .docx, .jpg, .png");
        return;
      }
    }

    try {
      const courseData = { name, description, teacherId: user.id };
      const response = await fetch("http://localhost:3001/courses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(courseData),
      });

      if (!response.ok) {
        throw new Error("Не удалось создать курс");
      }

      const course = await response.json();

      if (file) {
        const fileFormData = new FormData();
        fileFormData.append("file", file);
        const fileResponse = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: fileFormData,
        });

        if (!fileResponse.ok) {
          throw new Error("Не удалось загрузить файл");
        }

        const { filePath } = await fileResponse.json();
        await fetch("http://localhost:3001/files", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            courseId: course.id,
            fileName: file.name,
            filePath,
          }),
        });
      }

      dispatch(
        addNotification({
          id: Date.now(),
          userId: user.id,
          message: `Курс ${name} создан!`,
          createdAt: new Date().toISOString(),
        })
      );
      await fetch("http://localhost:3001/notifications", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId: user.id,
          message: `Курс ${name} создан!`,
          createdAt: new Date().toISOString(),
        }),
      });
      toast.success("Курс успешно создан!");
      navigate("/courses");
    } catch (error) {
      toast.error(error.message || "Сетевая ошибка при создании курса");
    }
  }

  return (
    <div className="container mx-auto p-6">
      <div className="bg-white p-6 rounded-lg shadow-md">
        <h1 className="text-3xl font-bold mb-6 text-gray-800">Создать курс (Только для преподавателей)</h1>
        <form className="flex flex-col gap-4">
          <input
            type="text"
            placeholder="Название курса"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
            className="p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            aria-label="Название курса"
          />
          <input
            type="text"
            placeholder="Описание"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
            className="p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            aria-label="Описание курса"
          />
          <input
            type="file"
            onChange={(e) => setFile(e.target.files[0])}
            accept=".pdf,.docx,.jpg,.png"
            className="p-2 border rounded-md"
            aria-label="Загрузить файл"
          />
          <button
            onClick={handleSubmit}
            className="bg-blue-600 text-white py-2 px-4 rounded-md hover:bg-blue-700 transition"
            aria-label="Создать курс"
          >
            Создать курс
          </button>
        </form>
      </div>
    </div>
  );
}

export default AddCourse;
